        syllables: 'Слоги',
        summary: 'Таблица',
        special: 'Спец.',
        elements: 'Элементы',
        numbers: 'Цифры',
        punctuation: 'Пункт.',
        rules: 'Чтение',
        harmony: 'Сингарм.',
        words: 'Слова',
        reading: 'Тексты',
        compose_word: 'Составить',
        write_word: 'Написать',
        direction: 'Штрихи',
        copybook: 'Пропись',
        practice_vowels: 'Гласные',
