    // Тематические наборы для тренировки. cats: null = все знаки (общий блок).
    // Гласные намеренно разделены на два блока (как и в курсе, см. courseStages):
    // сперва 7 базовых гласных, и только потом долгие/дифтонги — это меньший
    // и более посильный первый шаг, чем все 21 знак сразу.
    const practiceScopes = {
        practice_vowels:          { title: 'Тренировка: гласные', desc: '7 базовых гласных — фундамент чтения. Выучите их зрительно, прежде чем переходить к долгим и дифтонгам.', cats: ['vowels'] },
        practice_long_vowels:     { title: 'Тренировка: долгие гласные', desc: 'Долгие гласные (аа, ээ, ии…) — переходите сюда, когда уверенно узнаёте базовые гласные.', cats: ['long_vowels'] },
        practice_diphthongs:      { title: 'Тренировка: дифтонги', desc: 'Сочетания гласных с «й» (айи, эйи, ойи…) — тренируйте отдельно от долгих гласных, чтобы не путать.', cats: ['diphthongs'] },
        practice_consonants:      { title: 'Тренировка: согласные', desc: 'Основные согласные буквы ойратского алфавита.', cats: ['consonants'] },
        practice_galik:            { title: 'Тренировка: галики', desc: 'Отдельные знаки-«галики» — варианты согласных для заимствованных (тибетских, санскритских) слов. Возвращайтесь сюда после того, как освоите основные согласные.', cats: ['galik'] },
        practice_syllables:       { title: 'Тренировка: слоги', desc: 'Слоги «согласный + гласный» — по одной серии за раз (как Н-ряд, Б-ряд…), а не все 145 сразу. Выберите серию ниже.', cats: ['syllables'] },
        practice_numbers:         { title: 'Тренировка: цифры', desc: 'Калмыцкие цифры от 0 до 9.', cats: ['numbers'] },
        practice:                 { title: 'Практика по всем знакам', desc: 'Все буквы, цифры и знаки вперемешку — общее повторение.', cats: null }
    };
    const PRACTICE_CATS = Object.keys(practiceScopes);

    // Принимаемые ответы для знаков, у которых в данных служебный ярлык,
    // а также для дублирующих/галиковых/узких форм — принимаем базовый звук.
    // Ключ — поле latin (оно есть у всех записей и уникально).
