        'b2':         { name: 'б (узкая форма)',   answers: ['б','b'] },
        'k1':         { name: 'к (твердорядная)',  answers: ['к','k'] },
        'k1_narrow':  { name: 'к (узкая форма)', answers: ['к','k'] },
        'k2':         { name: 'к (мягкорядная)',   answers: ['к','k'] },
